class FoodRatings {
public:
    unordered_map<string, pair<string, int>> food_map;
    unordered_map<string, set<pair<int, string>>> cuisine_map;

    FoodRatings(vector<string>& foods, vector<string>& cuisines, vector<int>& ratings) {
        for (int i = 0; i < foods.size(); i++) {
            food_map[foods[i]] = {cuisines[i], ratings[i]};
            cuisine_map[cuisines[i]].insert({-ratings[i], foods[i]});
        }
    }

    void changeRating(string food, int newRating) {
        string cuisine = food_map[food].first;
        cuisine_map[cuisine].erase({-food_map[food].second, food});
        food_map[food].second = newRating;
        cuisine_map[cuisine].insert({-newRating, food});
    }

    string highestRated(string cuisine) {
        return (*cuisine_map[cuisine].begin()).second;
    }
};

